module RefModule(
	input [4:0] a,
	input [4:0] b,
	input [4:0] c,
	input [4:0] d,
	input [1:0] s,
	output [4:0] r
    );reg [4:0] unused_data_temp;
		assign r = unused_data_temp;
		always @(a or b or c or d or s) begin
			if(s == 2'b00)
				unused_data_temp = a;
			else if(s == 2'b01)
				unused_data_temp = b;
			else if(s == 2'b10)
				unused_data_temp = c;
			else
				unused_data_temp = d;
		end

endmodule
